var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"크륵, 크으으……!","JPN":"グルル、グウウ……！","ENG":"Grrr, Khhhkkk...!","TWN":"咳呃，咳呃呃……！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"구원이…… 구원을 위해……!","JPN":"救いが……救いのために……！","ENG":"Salvation... For salvation...!","TWN":"為了……為了救贖……！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"공개 회선으로 전한다! 적들의 상태가 갑자기 이상해졌어!","JPN":"公開回線を通じて伝える！　敵の様子が急におかしくなった！","ENG":"Announcing through public channel! The enemy is behaving weirdly!","TWN":"這是來自公共頻道的通知——敵人的狀態突然變得很奇怪！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"절대 거리를 주지 마! 함부로 접근하게 놔뒀다간 뼈도 못 추려!","JPN":"決して距離を詰められるな！　無闇に接近しようものならひとたまりもない！","ENG":"Do not let them get close! The minute they close in, you won't last a second!","TWN":"不要給他們縮短距離的機會！要是放任他們接近，後果很危險！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"침식체로서 본색을 드러내기 시작했네요.","JPN":"侵食体としての本性を現し始めましたね。","ENG":"They started to reveal their true forms as C.O.s.","TWN":"終於開始露出侵蝕體的真面目了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"진형은 흐트러지지 않는 걸 봐선… 적의 지휘관이 전황을 위험하다고 판단한 거겠죠.","JPN":"陣形が崩れていないということは……敵の指揮官が戦況を危ないと判断したんでしょうね。","ENG":"Seeing that their formation is intact... Their commander must have considered this situation as a threat.","TWN":"但是隊形還沒有散開……就表示敵人的指揮官認為戰況危急吧？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"대체 뭐야? 갑옷도 무기도, 우리와 똑같아.","JPN":"いったいなんだ？　鎧も武器も、俺たちとそっくりだ。","ENG":"What is that? They have the same weapons and armor as us.","TWN":"究竟是怎麼回事？鎧甲還有武器，都和我們一模一樣。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"역시 레드시프트 놈들이 관여한 것 아닐까?","JPN":"やっぱりレッドシフトの連中が関与しているんじゃ？","ENG":"Maybe Red Shift did interfere with this.","TWN":"他們會不會是紅移的那些傢伙？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"아무리 그 자들이라도 그렇지, 이건 너무 지나치잖아…….","JPN":"さすがの奴らでも、これは酷すぎるぜ……","ENG":"But this is too much, even for them...","TWN":"就算是那些人，這樣也太過分了吧……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……차마 눈 뜨고 볼 수 없군. 이건 기사의 정신을 모욕하는 행위다.","JPN":"……目も当てられないな。これは騎士の精神を侮辱する行為だ。","ENG":"...I can't bear to look at this. This is an insult to chivalry.","TWN":"……如此行徑，這是對騎士精神的侮辱。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 흔들리지 마십시오. 평기사들이 더 동요할 겁니다.","JPN":"団長、落ち着いてください。平騎士たちの動揺を煽ってしまいます。","ENG":"Do not get overwhelmed, Captain. The knight bachelors might get affected.","TWN":"團長，請不要動搖，否則會影響到平民騎士的士氣。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 가장 돌파력이 우수한 태스크포스는 그쪽인 것 같군요.","JPN":"今最も突破力が優秀なタスクフォースはそちらのようですね。","ENG":"It seems like you are the TASKFORCE with the most breakthrough force.","TWN":"現在突破能力最強的特遣勢力就是你們了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"적진 중심에 이 <color=#ffd34c>침식체 군집</color>을 지휘하는 개체가 있어요.","JPN":"敵陣の中心にこの<color=#ffd34c>侵食体の群れ</color>を指揮している個体がいます。","ENG":"There is an individual entity that's controlling the <color=#ffd34c>C.O. horde</color> in the middle of enemy territory.","TWN":"敵營中一定存在著指揮這個<color=#ffd34c>侵蝕體群</color>的個體。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 개체를 제압해야 합니다. 적어도 휘하 개체들을 통제하기 어렵게 만들어야 해요.","JPN":"その個体を制圧しなければなりません。少なくとも個体のコントロールを難しくする必要があります。","ENG":"We must take down that entity. We have to make it hard for it to control its underlings, at least.","TWN":"必須制伏那個個體。至少要讓他沒辦法指揮手下的個體才行。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"성공한다면 지금과 같이 통일된 움직임은 막을 수 있을 거랍니다.","JPN":"成功すれば今のように、統率の取れた動きはできなくできるでしょう。","ENG":"If we succeed, we will be able to stop their unified attacks.","TWN":"成功的話，就能阻止現在這樣統一的行動了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};